// Lấy text thuần; nếu không có thì chuyển HTML -> text dòng
let text = $json.text || $json.textPlain || '';
if (!text) {
  const html = $json.html || $json.textHtml || '';
  if (html) {
    text = String(html)
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/(p|div|tr|td|li|h\d|table|tbody|th)>/gi, '\n')
      .replace(/<[^>]+>/g, ' ');
  }
}

// Chuẩn hoá khoảng trắng
text = String(text)
  .replace(/\r/g, '\n')
  .replace(/\u00A0/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .replace(/ *\n+ */g, '\n')
  .trim();

// Lấy block từ "Ticket:" tới trước footer/link
const start = text.toLowerCase().indexOf('ticket:');
let block = start >= 0 ? text.slice(start) : text;

// Cắt phần footer/link (giả định)
const footer =
  block.match(/\n?\[\s*https?:\/\/[^\]]+\]/i) || // [https://...]
  block.match(/\n?to unsubscribe/i);
if (footer) block = block.slice(0, footer.index).trim();

// Helper: escape regex
const esc = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

// Cắt giữa nhãn A và nhãn kế tiếp (nếu có)
function capture(label, nextLabels) {
  const next = nextLabels.length ? `(?=(?:${nextLabels.map(esc).join('|')}))` : '$';
  const re = new RegExp(esc(label) + '\\s*:?\\s*([\\s\\S]*?)' + next, 'i');
  const m = block.match(re);
  if (!m) return null;
  return m[1]
    .replace(/\s*\n\s*/g, ' ')   // gộp xuống dòng trong giá trị
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

// 1) Ticket (chỉ lấy số dài)
const mTicket = block.match(/Ticket\s*:\s*(\d{5,})/i);
const ticket = mTicket ? mTicket[1].trim() : null;

// 2) Loại phiếu
const loaiPhieu =
  capture('Loại phiếu', ['Phòng ban xử lý', 'Noi dung phan anh', 'Nội dung phản ánh']) ||
  capture('Loai phieu', ['Phòng ban xử lý', 'Noi dung phan anh', 'Nội dung phản ánh']);

// 3) Phòng ban xử lý
const phongBan =
  capture('Phòng ban xử lý', ['Nội dung phản ánh', 'Noi dung phan anh', 'Ticket', 'Loại phiếu', 'Loai phieu']) ||
  capture('Phong ban xu ly', ['Nội dung phản ánh', 'Noi dung phan anh', 'Ticket', 'Loại phiếu', 'Loai phieu']);

// 4) Nội dung phản ánh (đến hết block)
let noiDung =
  capture('Nội dung phản ánh', []) ||
  capture('Noi dung phan anh', []);
if (noiDung) {
  // loại dấu [https://...] nếu còn sót
  noiDung = noiDung.replace(/\[\s*https?:\/\/[^\]]+\]/ig, ' ').replace(/[ \t]{2,}/g, ' ').trim();
}

// Chuỗi đã xuống dòng theo ý bạn
const formatted =
  `Ticket: ${ticket ?? ''}\n` +
  `Loại phiếu: ${loaiPhieu ?? ''}\n` +
  `Phòng ban xử lý: ${phongBan ?? ''}\n` +
  `Nội dung phản ánh: ${noiDung ?? ''}`;

return {
  json: { ticket, loaiPhieu, phongBan, noiDung, formatted }
};

